import { makeWLLAPIRequest } from '../utils/request'
import type { TeamInfo, TeamSeasonStats, TeamStanding } from './team.types'
import { PlayerData } from '../Players/player.types'
import { INFO_YEAR } from '../../Config'
import { WLL_ENDPOINTS } from '../utils/endpoints'

export const fetchWLLTeam = async (
  teamId: string,
  year?: number
): Promise<TeamInfo | null> => {
  try {
    const data = await makeWLLAPIRequest<TeamInfo>(WLL_ENDPOINTS.TEAM, {
      pathParams: { teamId },
      queryParams: { year: year ?? INFO_YEAR },
    })
    if (!data || Array.isArray(data)) {
      return null
    }
    return data
  } catch {
    return null
  }
}

export const fetchWLLTeamRoster = async (
  teamId: string,
  year: number
): Promise<PlayerData[] | null> => {
  try {
    const items = await makeWLLAPIRequest<PlayerData>(WLL_ENDPOINTS.TEAM_ROSTER, {
      pathParams: { teamId },
      queryParams: { year },
    })
    if (!items || !Array.isArray(items)) {
      return null
    }
    return items
  } catch {
    return null
  }
}

/** Fetch WLL standings (GET /api/v1/standings). */
export async function fetchWLLStandings(
  year: number,
  champSeries: boolean
): Promise<TeamStanding[] | null> {
  try {
    const items = await makeWLLAPIRequest<TeamStanding>(WLL_ENDPOINTS.STANDINGS, {
      queryParams: { year, champSeries },
    })
    if (!items || !Array.isArray(items)) {
      return null
    }
    return items
  } catch {
    return null
  }
}

/**
 * Fetch WLL team season stats (GET /api/v1/teams/season-stats).
 */
export async function fetchTeamSeasonStats(
  year: number,
  seasonSegment: string
): Promise<TeamSeasonStats[]> {
  try {
    const items = await makeWLLAPIRequest<TeamSeasonStats>(
      WLL_ENDPOINTS.TEAM_SEASON_STATS,
      { queryParams: { year, seasonSegment } }
    )
    if (!items || !Array.isArray(items)) {
      return []
    }
    return items
  } catch {
    return []
  }
}
