import { getBrazeSDK } from '../../Config/Braze/braze.config'
import { BRAZE_EVENTS } from '../../Constants/analytics'
import { executeWithRetry } from '../network/networkHelpers'
import { logEvent } from './firAnalytics'

export const logBrazeEvent = async (name: string, params?: any | undefined) => {
  try {
    const braze = await import('@braze/web-sdk')
    //Add league param
    params = params ? { ...params, league: 'wll' } : { league: 'wll' }
    braze.logCustomEvent(name, params)
  } catch (e) {
    console.log('Braze SDK load error:', e)
  }
}


export const logBrazeError = (event: string, params?: Record<string, unknown>) => {
  logEvent(event, {
    ...(params ?? {}),
    provider: 'braze',
    product: 'web_main',
  })
}

export const logBrazePageView = async (
  pageName: string,
  additionalParams?: Record<string, any>
) => {
  await executeWithRetry(async () => {
    const braze = await getBrazeSDK()
    if (!braze) throw new Error('Braze SDK not available')
    const eventName = BRAZE_EVENTS.page_view + pageName
    const eventParams = {
      page_name: pageName,
      ...additionalParams,
    }
    braze.logCustomEvent(eventName, eventParams)
  }, `log Braze page view: ${pageName}`)
}

export const setBrazeAttribute = async (attributeName: string, property: any) => {
  try {
    const braze = await import('@braze/web-sdk')
    const brazeUser = braze.getUser()
    if (brazeUser) {
      brazeUser.setCustomUserAttribute(attributeName, property)
    }
  } catch (e) {
    console.log(e)
  }
}
