import { useState, useEffect, useRef } from 'react'
import { RecaptchaVerifier, type ApplicationVerifier } from 'firebase/auth'
import { getFirAuth } from '../../Api/firebase/firebaseConnect'
import { configureFirebaseForDevelopment, handleAuthError, logEvent } from '../../Utils'
import { ANALYTICS_TAGS } from '../../Constants/analytics'

const waitForElement = (id: string, timeoutMs: number): Promise<HTMLElement | null> => {
  return new Promise((resolve) => {
    const el = document.getElementById(id)
    if (el) {
      resolve(el)
      return
    }
    const observer = new MutationObserver(() => {
      const found = document.getElementById(id)
      if (found) {
        observer.disconnect()
        resolve(found)
      }
    })
    observer.observe(document.body, { childList: true, subtree: true })
    setTimeout(() => {
      observer.disconnect()
      resolve(document.getElementById(id))
    }, timeoutMs)
  })
}

type Deferred<T> = {
  promise: Promise<T>
  resolve: (value: T) => void
  reject: (err: unknown) => void
}

function createDeferred<T>(): Deferred<T> {
  let resolve!: (value: T) => void
  let reject!: (err: unknown) => void
  const promise = new Promise<T>((res, rej) => {
    resolve = res
    reject = rej
  })
  return { promise, resolve, reject }
}

export const useRecaptcha = (
  containerId: string,
  shouldInitialize = true,
  _onSolved?: () => void
) => {
  const [ready, setReady] = useState(false)
  const verifierRef = useRef<RecaptchaVerifier | null>(null)
  const initOnce = useRef(false)
  const deferredRef = useRef<Deferred<ApplicationVerifier> | null>(null)
  if (!deferredRef.current) {
    deferredRef.current = createDeferred() as Deferred<ApplicationVerifier>
  }

  useEffect(() => {
    let cancelled = false
    if (!shouldInitialize || initOnce.current) return

    const init = async () => {
      try {
        await configureFirebaseForDevelopment()
        // Element only exists when sign-in modal is open + phone tab selected. Allow time for user to open modal.
        const el = await waitForElement(containerId, 30000)
        if (!el || cancelled) {
          const err = new Error(
            `Recaptcha container "${containerId}" not found. Ensure sign-in modal is open and phone tab is selected before init.`
          )
          deferredRef.current!.reject(err)
          return
        }

        const auth = await getFirAuth()
        if (!auth || cancelled) {
          deferredRef.current!.reject(
            new Error('Firebase auth not available for Recaptcha init')
          )
          return
        }

        initOnce.current = true
        const verifier = new RecaptchaVerifier(auth, containerId, {
          size: 'invisible',
        })

        if (!cancelled) {
          verifierRef.current = verifier
          setReady(true)
          deferredRef.current!.resolve(verifier)
        }
      } catch (err) {
        if (!cancelled) {
          handleAuthError(ANALYTICS_TAGS.auth_change_error, err, 'useRecaptcha_init')
          logEvent(ANALYTICS_TAGS.recaptcha_init_failed, {
            element: containerId,
            product: 'wll',
          })
          deferredRef.current!.reject(err)
        }
      }
    }

    init()
    return () => {
      cancelled = true
      if (verifierRef.current) {
        verifierRef.current.clear()
        verifierRef.current = null
      }
    }
  }, [containerId, shouldInitialize])

  const waitForVerifier = (): Promise<ApplicationVerifier> => {
    if (verifierRef.current) {
      return Promise.resolve(verifierRef.current)
    }
    return deferredRef.current!.promise
  }

  const ensureRendered = async (): Promise<void> => {
    const verifier = (await waitForVerifier()) as RecaptchaVerifier
    try {
      await verifier.render()
    } catch {
      // Already rendered
    }
  }

  return { ready, waitForVerifier, ensureRendered }
}
