import type { InAppMessage, ControlMessage } from '@braze/web-sdk'
import { isDevEnvironment } from '../WindowHelpers/windowHelpers'

export type BrazeMessage = InAppMessage | ControlMessage

/**
 * Default message handler that auto-shows in-app messages
 * @param braze Braze SDK instance
 * @param message The received message
 */
export const defaultInAppMessageHandler = (braze: any, message: BrazeMessage): void => {
  if (isDevEnvironment()) {
    console.log('[Braze IAM] Handling message with default handler:', message)
  }

  // Auto-show messages that have closeMessage method (InAppMessage type)
  if ('closeMessage' in message) {
    if (isDevEnvironment()) {
      console.log('[Braze IAM] Auto-showing in-app message')
    }
    if (typeof braze.showInAppMessage === 'function') {
      braze.showInAppMessage(message)
    }
  }
}

/**
 * Creates a subscription to Braze in-app messages
 * @param braze Braze SDK instance
 * @param onMessage Message handler function (defaults to auto-show)
 * @returns subscription ID
 */
export const subscribeToInAppMessages = (
  braze: any,
  onMessage?: (message: BrazeMessage) => void
): string | undefined => {
  if (typeof braze.subscribeToInAppMessage !== 'function') return undefined

  if (isDevEnvironment()) {
    console.log('[Braze IAM] Creating subscription')
  }

  const subscriptionId = braze.subscribeToInAppMessage((message: BrazeMessage) => {
    if (isDevEnvironment()) {
      console.log('[Braze IAM] Received message:', message)
    }

    if (onMessage) {
      onMessage(message)
    } else {
      defaultInAppMessageHandler(braze, message)
    }
  })

  if (isDevEnvironment()) {
    console.log('[Braze IAM] Subscription ID:', subscriptionId)
  }

  return subscriptionId
}

/**
 * Requests immediate data flush from Braze (fetches pending messages)
 * @param braze Braze SDK instance
 */
export const requestInAppMessageFlush = (braze: any): void => {
  if (typeof braze?.requestImmediateDataFlush === 'function') {
    if (isDevEnvironment()) {
      console.log('[Braze IAM] Requesting immediate data flush')
    }
    braze.requestImmediateDataFlush()
  }
}
