import { useCallback } from 'react'
import type { ApplicationVerifier } from 'firebase/auth'
import { signInWithPhoneNumber } from 'firebase/auth'
import { getFirAuth } from '../../Api/firebase/firebaseConnect'
import {
  AUTH_TIMEOUT,
  handleAuthError,
  isNavigatorOnline,
  withAuthTimeout,
  validatePhoneNumber,
  logEvent,
} from '../../Utils'
import { PHONE_ERROR_MESSAGES } from '../../Constants/auth'
import { ANALYTICS_TAGS } from '../../Constants/analytics'
import { useRecaptcha } from './useRecaptcha'
import type { PhoneAuthOperations } from './types'

export const usePhoneAuth = (
  shouldInitializeRecaptcha = true,
  toggleShowSnackbar: (snackbarData: {
    text: string
    color: 'red' | 'blue' | 'green'
  }) => void
): PhoneAuthOperations => {
  const { waitForVerifier, ensureRendered } = useRecaptcha(
    'phone-signin-btn',
    shouldInitializeRecaptcha
  )

  const sendPhoneVerification = useCallback(
    async (phoneNumber: string) => {
      try {
        if (!validatePhoneNumber(phoneNumber)) {
          handleAuthError(
            ANALYTICS_TAGS.login_error,
            PHONE_ERROR_MESSAGES.INVALID_PHONE_NUMBER,
            'sendPhoneVerification',
            { provider: 'phone' }
          )
          toggleShowSnackbar({
            text: PHONE_ERROR_MESSAGES.INVALID_PHONE_NUMBER,
            color: 'red',
          })
          return null
        }

        if (!isNavigatorOnline()) {
          toggleShowSnackbar({
            text: PHONE_ERROR_MESSAGES.NETWORK_REQUIRED,
            color: 'red',
          })
          return null
        }

        const auth = await withAuthTimeout(
          getFirAuth(),
          AUTH_TIMEOUT,
          'getFirAuth for phone verification'
        )

        if (!auth) {
          handleAuthError(
            ANALYTICS_TAGS.auth_change_error,
            'Firebase auth not available',
            'sendPhoneVerification'
          )
          toggleShowSnackbar({
            text: PHONE_ERROR_MESSAGES.SERVICE_UNAVAILABLE,
            color: 'red',
          })
          return null
        }

        const verifier = await waitForVerifier()
        await ensureRendered()

        const confirmationResult = await signInWithPhoneNumber(
          auth,
          phoneNumber,
          verifier as ApplicationVerifier
        )

        logEvent(ANALYTICS_TAGS.login_verification_send, {
          verification_method: 'phone',
        })

        return confirmationResult
      } catch (error) {
        handleAuthError(ANALYTICS_TAGS.login_error, error, 'sendPhoneVerification', {
          provider: 'phone',
        })
        toggleShowSnackbar({
          text: PHONE_ERROR_MESSAGES.VERIFICATION_FAILED,
          color: 'red',
        })
        return null
      }
    },
    [waitForVerifier, ensureRendered, toggleShowSnackbar]
  )

  return { sendPhoneVerification }
}
