import React, {
  createContext,
  useEffect,
  useMemo,
  useCallback,
  useContext,
} from 'react'
import { isSignInWithEmailLink } from 'firebase/auth'
import { SignInModal, EmailPromptDialog } from '../../Components/Auth'
import { getFirAuth } from '../../Api/firebase/firebaseConnect'
import { useQuery, useCookieStorage, configureFirebaseForDevelopment } from '../../Utils'
import { ANALYTICS_TAGS } from '../../Constants/analytics'
import { logEvent } from '../../Utils'
import {
  useAuthState,
  useAuthOperations,
  useFirebaseAuthListener,
  useGoogleAuth,
  useEmailAuth,
  useEmailPrompt,
  usePhoneAuth,
} from '../../Hooks/auth'
import { useSnackbarContext } from '../SnackbarContext/SnackbarContext'
import { useLinkContext } from '../LinkContext'
import type { AuthContextType, AuthProviderProps } from './types'
import { NO_USER } from '../../Api/firebase/AuthData'

export const AuthContext = createContext<AuthContextType | null>(null)

export const AuthProvider: React.FC<AuthProviderProps> = ({ children }) => {
  const query = useQuery()
  const { getCookie, setCookie, removeCookie } = useCookieStorage()
  const { toggleShowSnackbar, showFirebaseErrorSnackbar } = useSnackbarContext()
  const { sendMasterBrazeEvents } = useLinkContext()

  const authState = useAuthState()
  const {
    user,
    userFavorites,
    authLoading,
    showLogin,
    brazeInitialized,
    setUser,
    setUserFavorites,
    setAuthLoading,
    setShowLogin,
    setSignInFlowStep,
    setShowEmailPrompt,
    setBrazeInitialized,
    updateFavsInState,
    updateProfileInState,
    updateUserFieldInState,
    clearTeamFavorite,
    resetAuthState,
    login,
    handleToggleLogin,
    getMissingUserFields,
    showEmailPrompt,
  } = authState

  const authStateSetters = useMemo(
    () => ({
      setUser,
      setUserFavorites,
      setAuthLoading,
      setShowLogin,
      resetAuthState,
      setSignInFlowStep,
      setBrazeInitialized,
    }),
    [
      setUser,
      setUserFavorites,
      setAuthLoading,
      setShowLogin,
      resetAuthState,
      setSignInFlowStep,
      setBrazeInitialized,
    ]
  )

  const authOperations = useAuthOperations(toggleShowSnackbar, authStateSetters)
  const googleAuth = useGoogleAuth(toggleShowSnackbar, setShowLogin)
  const emailPrompt = useEmailPrompt({ setShowEmailPrompt })
  const emailAuth = useEmailAuth(
    toggleShowSnackbar,
    getCookie,
    setCookie,
    removeCookie,
    emailPrompt.promptForEmail
  )
  const phoneAuth = usePhoneAuth(true, toggleShowSnackbar)

  const sendMasterBrazeEventsWrapper = useCallback(
    (_params?: { isLoggedIn?: boolean }) => {
      sendMasterBrazeEvents()
    },
    [sendMasterBrazeEvents]
  )

  useFirebaseAuthListener({
    authOperations,
    googleAuth,
    authStateSetters,
    sendMasterBrazeEvents: sendMasterBrazeEventsWrapper,
    showFirebaseErrorSnackbar,
    login,
  })

  useEffect(() => {
    const init = async () => {
      configureFirebaseForDevelopment().catch(() => {
        // Ignore dev config errors
      })
      await authOperations.waitForAuth()
      await authOperations.getAuthRedirectResult()

      const auth = await getFirAuth()
      if (!auth) return

      const fbctQuery = query.get('fbct')
      if (fbctQuery) {
        await authOperations.handleCustomToken(fbctQuery)
      }

      if (isSignInWithEmailLink(auth, window.location.href)) {
        await emailAuth.handleEmailLink()
      }

      googleAuth.initializeGSI()
    }
    init()
  }, [])

  const signInWithSocial = useCallback(
    async (provider: string) => {
      if (provider !== 'google') return
      try {
        await googleAuth.signInWithGooglePopup()
      } catch (err) {
        logEvent(ANALYTICS_TAGS.login_error, {
          provider,
          error: err,
          product: 'wll-web',
        })
        setShowLogin({ show: false, extraFields: [] })
        throw err
      }
    },
    [googleAuth, setShowLogin]
  )

  const contextValue = useMemo<AuthContextType>(
    () => ({
      ...(user ?? NO_USER),
      userId: user?.userId ?? user?.uid ?? null,
      ...userFavorites,
      authLoading,
      brazeInitialized,
      login,
      handleToggleLogin,
      logout: authOperations.logout,
      updateFavsInState,
      updateProfileInState,
      updateUserFieldInState,
      clearTeamFavorite,
      getAuthToken: authOperations.getAuthToken,
      getMissingUserFields,
      signInWithSocial,
      signInWithEmLink: emailAuth.signInWithEmLink,
      sendPhoneVerification: phoneAuth.sendPhoneVerification,
    }),
    [
      user,
      userFavorites,
      authLoading,
      brazeInitialized,
      login,
      handleToggleLogin,
      authOperations.logout,
      authOperations.getAuthToken,
      updateFavsInState,
      updateProfileInState,
      updateUserFieldInState,
      clearTeamFavorite,
      getMissingUserFields,
      signInWithSocial,
      emailAuth.signInWithEmLink,
      phoneAuth.sendPhoneVerification,
    ]
  )

  return (
    <AuthContext.Provider value={contextValue}>
      {showLogin.show && (
        <SignInModal
          onClose={() => {
            logEvent(ANALYTICS_TAGS.login_cancelled)
            handleToggleLogin()
          }}
          signInWithSocial={signInWithSocial}
          signInWithEmLink={emailAuth.signInWithEmLink}
          extraFields={showLogin.extraFields}
        />
      )}
      {showEmailPrompt && (
        <EmailPromptDialog
          onConfirm={emailPrompt.handleEmailPromptConfirm}
          onCancel={emailPrompt.handleEmailPromptCancel}
        />
      )}
      {children}
    </AuthContext.Provider>
  )
}

export const useAuthContext = (): AuthContextType => {
  try {
    const context = useContext(AuthContext)
    if (!context) {
      throw new Error(
        'useAuthContext must be used within an AuthProvider. Make sure your component is wrapped with AuthProvider.'
      )
    }
    return context
  } catch (error) {
    console.error('Error in useAuthContext:', error)
    throw error
  }
}

