import React, { useState, useEffect } from 'react'
import { SnackBarStyle } from './styles'
import type { SnackbarOrigin } from '@mui/material/Snackbar'
import { Snackbar } from '../LazyComponents'
type SnackbarProps = {
  text: string
  color: 'red' | 'blue' | 'green'
  show: boolean
}

export interface State extends SnackbarOrigin {
  open: boolean
}

export const GeneralSnackbar: React.FC<SnackbarProps> = ({ text, color, show }) => {
  const [state, setState] = useState<State>({
    open: false,
    vertical: 'bottom',
    horizontal: 'center',
  })
  const { vertical, horizontal, open } = state

  useEffect(() => {
    setState({
      open: show,
      vertical: 'bottom',
      horizontal: 'center',
    })
  }, [])

  const handleClose = () => {
    setState({ ...state, open: false })
  }

  return (
    <Snackbar
      autoHideDuration={5000}
      anchorOrigin={{ vertical, horizontal }}
      open={open}
      onClose={handleClose}
      key={vertical + horizontal}
    >
      <SnackBarStyle color={color}>
        <p>{text}</p>
      </SnackBarStyle>
    </Snackbar>
  )
}
