export const getFeedItemById = async (
  params: GetFeedParams
): Promise<{ data: FeedItem | null; error: string | null | undefined } | null> => {
  try {
    const response = await makeAPIRequest(API_ENDPOINTS.GET_FEED_BY_ID, {
      method: 'GET',
      apiVersion: '3',
      queryParams: params as QueryParams,
    })
    if (!response?.data || response?.error) {
      return {
        data: null,
        error: response?.error?.message ?? 'Could not get item.',
      }
    }
    return {
      data: response.data,
      error: null,
    }
  } catch (err: any) {
    console.log(err)
    return {
      data: null,
      error: err?.error,
    }
  }
}
