/**
 * Get team image checking for allstar season or regular season
 * @param teamName - Team name
 * @param year - Year
 * @param segment - Season segment
 * @returns Team image
 */
export const getTeamImage = (
  teamName: string,
  year?: number,
  segment?: SeasonType | undefined
): string => {
  if (segment === SEASON_SEGMENT_NAMES.allstar) {
    return getAsgTeamIc(teamName, year ?? CURRENT_YEAR)
  }
  return getTeamIc(teamName, year)
}

/**
 * Get team image for regular season
 * @param teamName - Team name
 * @param year - Year
 * @returns Team image
 */
export const getTeamIc = (teamName: string | undefined, year?: number): string => {
  if (!teamName) return getGeneralTeamIc()
  const formattedTeam = formatTeamForImage(teamName)

  if (!formattedTeam) return getGeneralTeamIc()
  return TEAM_LOGO_IMAGES[formattedTeam] ?? getGeneralTeamIc()
}

/**
 * Get team image for allstar season
 * @param teamName - Team name
 * @param year - Year
 * @returns Team image
 */
export const getAsgTeamIc = (teamName: string | undefined, year: number): string => {
  if (!teamName) return getGeneralTeamIc()
  const yearStr = year.toString()
  const formattedTeam = formatTeamForImage(teamName)
  if (!formattedTeam) return getGeneralTeamIc()

  const yearData = WLL_ASG_TEAM_LOGO_IMAGES[yearStr]
  if (!yearData) return getTeamIc(teamName, year)

  return yearData[formattedTeam] ?? getTeamIc(teamName, year)
}

/**
 * Convert team code and format team name for image
 * @param teamName - Team name
 * @returns Formatted team name
 */
const formatTeamForImage = (teamName: string): string => {
  if (!teamName) return ''
  let processedName = teamName
  if (teamName.length <= 4) {
    const fullName = getFullTeamName(teamName)
    if (fullName) {
      processedName = fullName
    }
  }
  return processedName.toLowerCase()
}

