import { logEvent } from '../Analytics/firAnalytics'

export type AppError = {
  message: string
  code?: string | number
  details?: unknown
}

/**
 * Handle an auth-related error: log to analytics and console
 */
export const handleAuthError = (
  analyticsTag: string,
  error: unknown,
  context: string,
  extraParams: Record<string, unknown> = {}
): AppError => {
  const normalized = normalizeError(error)

  logEvent(analyticsTag, {
    error: normalized,
    context,
    product: 'wll',
    ...extraParams,
  })

  console.error(`[Auth Error – ${context}]`, error)
  return normalized
}

export const normalizeError = (err: unknown): AppError => ({
  message: err instanceof Error ? err.message : String(err),
  code:
    err instanceof Error && 'code' in err ? (err.code as string | number) : undefined,
  details: err,
})