import React, {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useRef,
  useState,
} from 'react'
import { getBrazeSDK, initBrazeCore } from '../../Config/Braze/braze.config'
import { BrazePageTrackingComponent } from '../../Hooks/braze/useBrazePageTracking'
import { type BrazeMessage, isDevEnvironment, subscribeToInAppMessages } from '../../Utils'
import { useAuthContext } from '../AuthContext'

type BrazeContextType = {
  brazeInitialized: boolean
  brazeError: Error | null
}

export const BrazeContext = createContext<BrazeContextType | null>(null)

export const useBraze = () => {
  const context = useContext(BrazeContext)
  if (!context) {
    throw new Error('useBraze must be used within a BrazeProvider')
  }
  return context
}

type BrazeProviderProps = {
  children: React.ReactNode
}

export const BrazeProvider: React.FC<BrazeProviderProps> = ({ children }) => {
  const [brazeInitialized, setBrazeInitialized] = useState<boolean>(false)
  const [brazeError, setBrazeError] = useState<Error | null>(null)
  const { userId, authLoading } = useAuthContext()
  const [pendingMessage, setPendingMessage] = useState<BrazeMessage | null>(null)
  const subscriptionIdRef = useRef<string | undefined>(undefined)

  const startBraze = useCallback(async () => {
    if (isDevEnvironment()) {
      console.log('[Braze] Starting Braze')
    }
    if (authLoading) return
    try {
      const braze = await getBrazeSDK()
      if (!braze) {
        throw new Error('Failed to load Braze SDK')
      }

      // Pass user ID if authenticated, undefined if anonymous
      const uid = userId ?? undefined

      if (isDevEnvironment()) {
        console.log('[Braze] Initializing with userId:', uid || 'anonymous')
      }

      const success = await initBrazeCore(uid, preSessionSetup)
      if (!success) {
        throw new Error('Failed to initialize Braze core')
      }

      setBrazeInitialized(true)
      setBrazeError(null)

      if (isDevEnvironment()) {
        console.log(
          '[Braze] Successfully initialized with user:',
          uid ? 'authenticated' : 'anonymous'
        )
        console.log('[Braze] Braze SDK methods available:', Object.keys(braze))
      }
    } catch (error) {
      console.error('[Braze] Initialization failed:', error)
      setBrazeError(
        error instanceof Error ? error : new Error('Unknown error initializing Braze')
      )
      setBrazeInitialized(false)
    }
  }, [userId, authLoading])

  useEffect(() => {
    // Wait for auth before initializing Braze
    if (!authLoading) {
      if (isDevEnvironment()) {
        console.log('[Braze] Auth completed, initializing Braze. User state:', {
          hasUserId: !!userId,
        })
      }
      startBraze()
    }
  }, [authLoading, userId, startBraze])

    // Pre-session setup, subscribe, don't auto-show
    const preSessionSetup = (braze: any) => {
      // Cleanup any existing subscription
      if (subscriptionIdRef.current && typeof braze?.removeSubscription === 'function') {
        braze.removeSubscription(subscriptionIdRef.current)
        subscriptionIdRef.current = undefined
      }
  
      subscriptionIdRef.current = subscribeToInAppMessages(braze, (message) => {
        setPendingMessage(message)
      })
    }

    // After session start, show pending
    useEffect(() => {
      const showPending = async () => {
        if (!brazeInitialized || !pendingMessage) return
        // Only show real InAppMessage
        if ('closeMessage' in pendingMessage) {
          const braze = await getBrazeSDK()
          if (braze) {
            try {
              braze.showInAppMessage(pendingMessage)
              setPendingMessage(null)
            } catch (e) {
              console.error('[Braze] Failed to show in-app message after session:', e)
            }
          }
        }
      }
      void showPending()
    }, [brazeInitialized, pendingMessage])
  
    // Remove subscription on unmount
    useEffect(() => {
      return () => {
        const cleanup = async () => {
          const braze = await getBrazeSDK()
          if (
            braze &&
            subscriptionIdRef.current &&
            typeof braze?.removeSubscription === 'function'
          ) {
            try {
              braze.removeSubscription(subscriptionIdRef.current)
            } catch (e) {
              console.warn('[Braze] Failed to remove IAM subscription on unmount', e)
            } finally {
              subscriptionIdRef.current = undefined
            }
          }
        }
        void cleanup()
      }
    }, [])

  const contextValue = {
    brazeInitialized,
    brazeError,
  }

  return (
    <BrazeContext.Provider value={contextValue}>
      {children}
      {brazeInitialized && (
        <>
          <BrazePageTrackingComponent brazeInitialized={brazeInitialized} />
        </>
      )}
    </BrazeContext.Provider>
  )
}
