import { homeCalloutList } from "../../Constants/callouts"

export const getHomeFullImageCallout = () => {
    const now = new Date().getTime() / 1000
    const liveCallout = homeCalloutList.find((callout) => callout.startTime < now && callout.endTime > now)

    if(!liveCallout) return homeCalloutList[0] // Return default
    return liveCallout

}