import { STORAGE_NAMES } from '../../Constants/storage'
import { isLocalStorageEnabled } from '../WindowHelpers/windowHelpers'

/**
 * Retrieves the temporary email address stored during the email link sign-in
 */
export const getStoredTempEmail = (
  getCookie: (name: string) => string | null
): string => {
  let email = ''

  if (typeof window !== 'undefined' && window.localStorage) {
    email = window.localStorage.getItem(STORAGE_NAMES.tempEmail) || ''
  }
  if (!email) {
    const cookieEm = getCookie(STORAGE_NAMES.tempEmail)
    if (cookieEm) {
      email = cookieEm
    }
  }

  return email.toLowerCase()
}

/**
 * Stores the temporary email address for the email link sign-in
 */
export const setStoredTempEmail = (
  email: string,
  setCookie: (name: string, value: string) => void
): void => {
  if (isLocalStorageEnabled()) {
    window.localStorage.setItem(STORAGE_NAMES.tempEmail, email)
  }
  setCookie(STORAGE_NAMES.tempEmail, email)
}

/**
 * Removes the temporary email address from all storage locations
 */
export const removeStoredTempEmail = (
  removeCookie: (name: string) => void
): void => {
  if (isLocalStorageEnabled()) {
    window.localStorage.removeItem(STORAGE_NAMES.tempEmail)
  }
  removeCookie(STORAGE_NAMES.tempEmail)
}
