import { makeAPIRequest, makeWLLAPIRequest } from '../utils/request'
import type {
  EventGQL,
  PlayLog,
} from './events.types'
import { API_ENDPOINTS, WLL_ENDPOINTS } from '../utils/endpoints'
import { TeamGameStats } from '../Teams/team.types'
import { PlayerGameData } from '../Players/player.types'

export const fetchWLLSeasonEvents = async (year: number, includeCS?: boolean): Promise<EventGQL[] | null> => {
  try {
    const items = await makeWLLAPIRequest<EventGQL>(WLL_ENDPOINTS.EVENTS, {
      queryParams: { year, includeCS },
    })
    if (!items || !Array.isArray(items)) {
      return null
    }
    return items
  } catch {
    return null
  }
}

/**
 * Fetch all event info for specific season
 */
export async function fetchPLLSeasonEvents(
  season: number,
): Promise<EventGQL[]> {
  try {
    const evRes = await makeAPIRequest(API_ENDPOINTS.PLL_SEASON_EVENTS, {
      method: 'GET',
      apiVersion: '4',
      queryParams: {
        year: season,
        includeCS: false
      },
    })
    if (evRes?.error) {
      evRes.error?.message && console.error(evRes.error?.message)
      return []
    }
    return evRes?.data
  } catch (error) {
    return []
  }
}

/**
 * Fetch all event info for specific event
 * @param slug - id of the single event
 */
export async function fetchSingleEventInfo(slug: string): Promise<EventGQL | null> {
  try {
    const evRes = await makeAPIRequest(`${API_ENDPOINTS.SEASON_EVENTS}/${slug}`, {
      method: 'GET',
      apiVersion: '4'
    })
    if (evRes?.error) {
      evRes.error?.message && console.error(evRes.error?.message)
      return null
    }
    return evRes?.data
  } catch (error) {
    console.error('Error fetching event info:', error)
    return null
  }
}

/**
 * REST endpoint - Fetch stats for each team
 * @returns Two teams team[0] is away team
 */
export async function fetchEventTeamsStats(slug: string): Promise<TeamGameStats[]> {
  try {
    const teamsStatsRes = await makeAPIRequest(
      `${API_ENDPOINTS.SEASON_EVENTS}/${slug}/teams/stats`,
      {
        method: 'GET',
        apiVersion: '4',
      }
    )
    if (teamsStatsRes?.error) {
      teamsStatsRes.error?.message && console.error(teamsStatsRes.error?.message)
      return []
    }
    return teamsStatsRes?.data ?? []
  } catch (error) {
    console.error('Error fetching event teams stats:', error)
    return []
  }
}

