import { useEffect, useRef, startTransition } from 'react'
import { onAuthStateChanged } from 'firebase/auth'
import { getFirAuth } from '../../Api/firebase/firebaseConnect'
import {
  checkUserValidation,
  handleAuthError,
  handleFirebaseTransactionError,
  logEvent,
  normalizeError,
  resetFirebasePersistence,
  validateAuthInput,
} from '../../Utils'
import { NEW_USER_VALIDATION_CODE } from '../../Constants/auth'
import { ANALYTICS_TAGS } from '../../Constants/analytics'
import { NO_USER } from '../../Api/firebase/AuthData'
import type { AuthOperations, GoogleAuthOperations, AuthStateSetters } from './types'
import { DEFAULT_EXTRA_LOGIN_FIELDS } from '../../Api'
import { useSnackbarContext } from '../../Context/SnackbarContext/SnackbarContext'

type UseFirebaseAuthListenerParams = {
  authOperations: AuthOperations
  googleAuth: GoogleAuthOperations
  authStateSetters: AuthStateSetters
  sendMasterBrazeEvents: (params?: { isLoggedIn?: boolean }) => void
  showFirebaseErrorSnackbar: (refreshFn: () => void) => void
  login: (extraFields?: string[]) => void
}

export const useFirebaseAuthListener = ({
  authOperations,
  googleAuth,
  authStateSetters,
  sendMasterBrazeEvents,
  showFirebaseErrorSnackbar,
  login,
}: UseFirebaseAuthListenerParams) => {
  const { setUser, setAuthLoading, setUserFavorites, setSignInFlowStep, setShowLogin } =
    authStateSetters
  const { toggleShowSnackbar } = useSnackbarContext()

  const authChangeCounterRef = useRef(0)
  const toggleShowSnackbarRef = useRef(toggleShowSnackbar)
  const authOperationsRef = useRef(authOperations)
  const googleAuthRef = useRef(googleAuth)
  const sendMasterBrazeEventsRef = useRef(sendMasterBrazeEvents)
  const showFirebaseErrorSnackbarRef = useRef(showFirebaseErrorSnackbar)
  const loginRef = useRef(login)

  useEffect(() => {
    authOperationsRef.current = authOperations
    googleAuthRef.current = googleAuth
    sendMasterBrazeEventsRef.current = sendMasterBrazeEvents
    showFirebaseErrorSnackbarRef.current = showFirebaseErrorSnackbar
    loginRef.current = login
    toggleShowSnackbarRef.current = toggleShowSnackbar
  }, [authOperations, googleAuth, sendMasterBrazeEvents, showFirebaseErrorSnackbar, login, toggleShowSnackbar])

  useEffect(() => {
    let unsubscribe: (() => void) | null = null

    const authListener = async () => {
      const auth = await getFirAuth()
      if (!auth) return

      unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
        const thisChange = ++authChangeCounterRef.current
        const isStale = () => authChangeCounterRef.current !== thisChange

        try {
          if (firebaseUser && !firebaseUser.isAnonymous) {
            setAuthLoading(true)

            const providerId = firebaseUser.providerData[0]?.providerId
            if (!providerId) {
              startTransition(() => {
                setAuthLoading(false)
                setUser(NO_USER)
                auth.signOut()
              })
              return
            }

            const loginInput =
              providerId !== 'phone' ? firebaseUser.email : firebaseUser.phoneNumber

            logEvent(ANALYTICS_TAGS.verification_success, {
              flow: 'login',
              verification_method: providerId === 'phone' ? 'phone' : 'email',
            })

            const validityCode = await validateAuthInput(loginInput ?? null, false)
            if (isStale()) return

            const isValid = checkUserValidation(validityCode, toggleShowSnackbarRef.current)
            if (!isValid) {
              startTransition(() => {
                setAuthLoading(false)
                setUser(NO_USER)
                auth.signOut()
              })
              return
            }

            if (validityCode === NEW_USER_VALIDATION_CODE) {
              setSignInFlowStep(2)
              const isEmail = providerId !== 'phone'
              const extraFields = isEmail
                ? DEFAULT_EXTRA_LOGIN_FIELDS
                : ['email', ...DEFAULT_EXTRA_LOGIN_FIELDS]
              setShowLogin({ show: false, extraFields: [] })
              await authOperationsRef.current.handleUserChange()
              if (isStale()) return
              loginRef.current(extraFields)
              sendMasterBrazeEventsRef.current({ isLoggedIn: true })
              return
            }

            setShowLogin({ show: false, extraFields: [] })
            await authOperationsRef.current.handleUserChange()
            if (isStale()) return

            sendMasterBrazeEventsRef.current({ isLoggedIn: true })
          } else {
            googleAuthRef.current.handleGoogleOneTapPrompt(NO_USER)
            startTransition(() => {
              setUser(NO_USER)
              setUserFavorites({
                topics: [],
                favPlayers: [],
                favTeam: null,
                favWLLTeam: null,
              })
              setAuthLoading(false)
            })
            sendMasterBrazeEventsRef.current({ isLoggedIn: false })
          }
        } catch (error) {
          if (isStale()) return

          const errorMessage = normalizeError(error)
          if (handleFirebaseTransactionError(errorMessage.message, 'auth_state_change')) {
            const refreshFn = await resetFirebasePersistence()
            if (isStale()) return
            showFirebaseErrorSnackbarRef.current(refreshFn)
            return
          }

          handleAuthError(ANALYTICS_TAGS.auth_state_change_error, error, 'auth_state_change', {
            hasUser: !!firebaseUser,
          })
          startTransition(() => {
            setAuthLoading(false)
            setUser(NO_USER)
          })
        }
      })
    }

    authListener()

    return () => {
      if (unsubscribe) unsubscribe()
    }
  }, [setUser, setAuthLoading, setUserFavorites, setShowLogin, setSignInFlowStep])
}
