import { useState, useRef, useEffect } from 'react'
import {
  InputStyle,
  ErrorStyle,
  EmailPromptWrapper,
  EmailPromptContainer,
  EmailPromptButtonContainer,
  EmailPromptCancelButton,
  EmailPromptSubmitButton,
} from './styles'
import { validateEmail } from './authHelpers'
import { Head, Desc } from '../Typography/Text.styles'
import { colors } from '../consts'

type EmailPromptDialogProps = {
  onConfirm: (email: string) => void
  onCancel: () => void
}

export const EmailPromptDialog: React.FC<EmailPromptDialogProps> = ({
  onConfirm,
  onCancel,
}) => {
  const [email, setEmail] = useState<string>('')
  const [errorMsg, setErrorMsg] = useState<string>('')
  const inputRef = useRef<HTMLInputElement>(null)

  useEffect(() => {
    inputRef.current?.focus()
  }, [])

  const handleEmailChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
  ) => {
    const newEmail = e.target.value
    setEmail(newEmail)
    if (errorMsg) setErrorMsg('')
  }

  const handleSubmit = () => {
    const validated = validateEmail(email)
    if (validated.valid) {
      onConfirm(email.toLowerCase())
    } else {
      setErrorMsg(validated.errorMsg)
    }
  }

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleSubmit()
    if (e.key === 'Escape') onCancel()
  }

  return (
    <EmailPromptWrapper>
      <EmailPromptContainer
        role="dialog"
        aria-modal="true"
        aria-labelledby="email-prompt-title"
        aria-describedby="email-prompt-description"
      >
        <Head id="email-prompt-title" textColor={colors.text} vertMargins={4}>
          Enter your email
        </Head>
        <Desc id="email-prompt-description" textColor={colors.gray.gray70}>
          Enter the email that you used to sign in.
        </Desc>
        <InputStyle
          inputRef={inputRef}
          required
          type="email"
          variant="outlined"
          margin="normal"
          id="email-prompt-input"
          label="Email"
          value={email}
          onChange={handleEmailChange}
          onKeyDown={handleKeyDown}
          autoComplete="email"
          aria-label="Email address"
        />
        {errorMsg && <ErrorStyle>{errorMsg}</ErrorStyle>}
        <EmailPromptButtonContainer>
          <EmailPromptCancelButton onClick={onCancel}>Cancel</EmailPromptCancelButton>
          <EmailPromptSubmitButton onClick={handleSubmit}>
            Continue
          </EmailPromptSubmitButton>
        </EmailPromptButtonContainer>
      </EmailPromptContainer>
    </EmailPromptWrapper>
  )
}
