import { MasterLinkParams } from '../../Constants'
import { USER_VALIDATION_CODES } from '../../Constants/auth'
import { logEvent } from '../Analytics/firAnalytics'
import { ANALYTICS_TAGS } from '../../Constants/analytics'
import { normalizeError } from '../errors'
import { isBrowserEnvironment } from '../WindowHelpers/windowHelpers'

const FUNCTION_NAME = 'getUniqueInstallId'

/**
 * Gets the GA4 client_id from the _ga cookie.
 * Returns null if _ga cookie is unavailable or invalid.
 */
export const getUniqueInstallId = async (): Promise<string | null> => {
  if (!isBrowserEnvironment()) {
    return null
  }

  try {
    return getGaClientIdFromCookie()
  } catch (error) {
    const normalizedError = normalizeError(error)
    console.error(`Error in ${FUNCTION_NAME}:`, normalizedError)
    logEvent(ANALYTICS_TAGS.firebase_transaction_error, {
      function: FUNCTION_NAME,
      error: normalizedError.message,
    })
    return null
  }
}

/**
 * Parses the _ga cookie to extract the Google Analytics client ID.
 * The _ga cookie format is typically: GA1.2.{client_id}
 * @returns The client ID or null if not found or invalid
 */
const getGaClientIdFromCookie = (): string | null => {
  if (typeof document === 'undefined') {
    return null
  }

  // Check if cookies are enabled in the browser
  if (typeof navigator !== 'undefined' && navigator.cookieEnabled === false) {
    return null
  }

  // Cookie access check
  try {
    const cookieTest = document.cookie
    if (typeof cookieTest !== 'string') {
      return null
    }
  } catch (cookieAccessError) {
    return null
  }

  try {
    const cookies = document.cookie.split(';')
    if (cookies.length === 0 || (cookies.length === 1 && cookies[0].trim() === '')) {
      return null
    }

    for (const cookie of cookies) {
      const trimmedCookie = cookie.trim()

      if (trimmedCookie.startsWith('_ga=')) {
        const gaCookieValue = trimmedCookie.substring(4) // Remove '_ga=' prefix

        // Format: GA1.2.{client_id} or GA1.{domain_parts}.{client_id}
        const parts = gaCookieValue.split('.')

        if (parts.length >= 3 && parts[0] === 'GA1') {
          // The client ID last two parts joined with dot
          const clientId = parts.slice(-2).join('.')
          if (/^\d+\.\d+$/.test(clientId)) {
            return clientId
          }
        }
      }
    }

    return null
  } catch (error) {
    console.error('Error parsing _ga cookie:', error)
    return null
  }
}

export const determineMasterParamsToAdd = (
  mParams: MasterLinkParams | null,
  newUser: boolean
) => {
  if (!mParams) return null
  let linkParams: MasterLinkParams = mParams
  if (mParams?.osc) {
    linkParams.osc = mParams.osc
  }
  if (newUser) {
    if (mParams?.pllm_source) {
      linkParams.pllm_source = mParams.pllm_source
    }
    if (mParams?.referrerUserId) {
      linkParams.referrerUserId = mParams.referrerUserId
    }
  }
  return linkParams
}

const mapUserExistsCodeToMessage = (code: string): string | undefined => {
  const codeExists = Object.keys(USER_VALIDATION_CODES).includes(code)
  if (codeExists) {
    return USER_VALIDATION_CODES[code]
  }
  return undefined
}

export const checkUserValidation = (
  result: string | null,
  toggleShowSnackbar: (data: { text: string; color: 'red' | 'blue' | 'green' }) => void
): boolean => {
  try {
    if (result === null) {
      toggleShowSnackbar({
        text: 'Please try again later.',
        color: 'red',
      })
      return false
    }
    const errorMsg = mapUserExistsCodeToMessage(result)
    if (errorMsg) {
      toggleShowSnackbar({
        text: errorMsg,
        color: 'red',
      })
      return false
    }
    return true
  } catch (error) {
    console.error('Error checking user validation:', error)
    toggleShowSnackbar({
      text: 'Please try again later.',
      color: 'red',
    })
    return false
  }
}

/**
 * Validates auth input (email/phone) against backend.
 * Returns validation code: 'new_user' | 'existing_user' | error code string, or null on error.
 */
export const validateAuthInput = async (
  input: string | null,
  isCreateUser: boolean
): Promise<string | null> => {
  try {
    const { checkValidUser } = await import('../../Api/Users/users')
    return await checkValidUser(isCreateUser ? input : null)
  } catch (error) {
    const normalizedError = normalizeError(error)
    console.error('Error validating auth input:', normalizedError)
    return null
  }
}