import { getFirAnalytics } from '../../Api/firebase/firebaseConnect'

export const logEvent = async (name: string, params?: any | undefined) => {
    const { logEvent: firLogEvent } = await import('firebase/analytics')
    const fa = await getFirAnalytics()
    //Add league param
    params = params ? {...params, league: 'wll'} : {league: 'wll'}
    firLogEvent(fa, name, params)
}