import React, {
  createContext,
  useState,
  useEffect,
  useContext,
  useMemo,
  useCallback,
} from 'react'
import { fetchTeamSeasonStats, fetchPlayerSeasonStats } from '../../Api'
import type { TeamSeasonStats, PlayerSeasonStats } from '../../Api'
import { useSeasonContext } from '../SeasonContext/SeasonContext'
import type { Season } from '../SeasonContext/SeasonContext'
import { SEASON_SELECTOR_TYPES } from '../../Constants/season'

export type StatsTab = 'players' | 'teams'

type StatsContextType = {
  teamStats: TeamSeasonStats[]
  playerStats: PlayerSeasonStats[]
  isTeamStatsLoading: boolean
  isPlayerStatsLoading: boolean
  activeTab: StatsTab
  setActiveTab: (tab: StatsTab) => void
}

export const StatsContext = createContext<StatsContextType | null>(null)

export const StatsProvider: React.FC<React.PropsWithChildren<unknown>> = ({
  children,
}) => {
  const seasonContext = useSeasonContext()
  const seasonSelect = seasonContext?.seasonSelect?.[SEASON_SELECTOR_TYPES.MAIN]

  const [teamStats, setTeamStats] = useState<TeamSeasonStats[]>([])
  const [playerStats, setPlayerStats] = useState<PlayerSeasonStats[]>([])
  const [isTeamStatsLoading, setIsTeamStatsLoading] = useState<boolean>(true)
  const [isPlayerStatsLoading, setIsPlayerStatsLoading] = useState<boolean>(true)
  const [activeTab, setActiveTab] = useState<StatsTab>('players')

  const fetchAllStats = useCallback(
    async (season: Season) => {
      setIsTeamStatsLoading(true)
      setIsPlayerStatsLoading(true)

      const [teamRes, playerRes] = await Promise.allSettled([
        fetchTeamSeasonStats(season.year, season.seasonType),
        fetchPlayerSeasonStats(season.year, season.seasonType),
      ])

      if (teamRes.status === 'fulfilled') {
        setTeamStats(teamRes.value)
      }
      setIsTeamStatsLoading(false)

      if (playerRes.status === 'fulfilled') {
        const playersWithScoringPoints = playerRes.value.map((player) => {
          const scoringPoints =
            player.scoringPoints ??
            (player.twoPointGoals ?? 0) * 2 + (player.onePointGoals ?? 0)
          return { ...player, scoringPoints }
        })
        setPlayerStats(playersWithScoringPoints)
      }
      setIsPlayerStatsLoading(false)
    },
    [seasonSelect]
  )

  useEffect(() => {
    if (seasonSelect) {
      fetchAllStats(seasonSelect)
    }
  }, [seasonSelect?.year, seasonSelect?.seasonType, fetchAllStats])

  const contextValue: StatsContextType = useMemo(
    () => ({
      teamStats,
      playerStats,
      isTeamStatsLoading,
      isPlayerStatsLoading,
      activeTab,
      setActiveTab,
    }),
    [teamStats, playerStats, isTeamStatsLoading, isPlayerStatsLoading, activeTab]
  )

  return <StatsContext.Provider value={contextValue}>{children}</StatsContext.Provider>
}

export const useStatsContext = (): StatsContextType => {
  const context = useContext(StatsContext)
  if (!context) {
    throw new Error('useStatsContext must be used within a StatsProvider')
  }
  return context
}
