import type { TeamSeasonStats } from '../../Api'
import { ConvertStatValue } from '../formatting'

type TeamStatsRecord = Record<string, number | string | null | undefined>

function getRawValue(team: TeamStatsRecord, field: string): number | string | null | undefined {
  return team[field] ?? null
}

export function getTeamStatDisplayValue(
  team: TeamSeasonStats,
  field: string
): string | number {
  const raw = getRawValue(team, field)
  return ConvertStatValue(raw, field) as string | number
}

export function getTeamStatSortValue(team: TeamSeasonStats, field: string): number {
  const raw = getRawValue(team, field)
  if (typeof raw === 'number') return raw
  if (typeof raw === 'string') {
    const n = parseFloat(raw)
    return Number.isNaN(n) ? 0 : n
  }
  return 0
}
