import { useCallback, startTransition, useMemo } from 'react'
import { getFirAuth } from '../../Api/firebase/firebaseConnect'
import {
  signInWithCustomToken,
  getRedirectResult,
  getBrowserPopupRedirectResolver,
} from '../../Api/firebase/auth'
import { getFirebaseUser } from '../../Api/firebase/AuthData'
import {
  logBrazeEvent,
  withAuthTimeout,
  handleAuthError,
  clearQueryParams,
  logEvent,
} from '../../Utils'
import { ANALYTICS_TAGS } from '../../Constants/analytics'
import { AUTH_TIMEOUT } from '../../Utils/network/networkHelpers'
import { useLinkContext } from '../../Context'
import type { User } from '../../Api/Users/types'
import type { AuthOperations, AuthStateSetters } from './types'
import {
  fetchUserFromDB,
  setUserDataInState,
  handleAnonymousSignIn,
} from '../../Utils/auth/authOperations'
import { getUserId } from '../../Utils'

export const useAuthOperations = (
  toggleShowSnackbar: (snackbarData: {
    text: string
    color: 'red' | 'blue' | 'green'
  }) => void,
  authStateSetters: AuthStateSetters
): AuthOperations => {
  const { getMasterLinkParamsFromLocal } = useLinkContext()
  const { setUser, setUserFavorites, setAuthLoading, setShowLogin, resetAuthState, setBrazeInitialized } =
    authStateSetters

  const logout = useCallback(async (): Promise<void> => {
    try {
      const fba = await getFirAuth()
      if (!fba) {
        handleAuthError(
          ANALYTICS_TAGS.auth_change_error,
          'Firebase auth not available',
          'logout'
        )
        startTransition(() => setAuthLoading(false))
        return
      }
      startTransition(() => resetAuthState())
      await fba.signOut()
      await handleAnonymousSignIn()
      try {
        logBrazeEvent(ANALYTICS_TAGS.log_out)
        logEvent(ANALYTICS_TAGS.log_out)
      } catch {
        // ignore
      }
    } catch (error) {
      handleAuthError(ANALYTICS_TAGS.auth_change_error, error, 'logout')
      startTransition(() => setAuthLoading(false))
    }
  }, [resetAuthState, setAuthLoading])

  const handleUserChange = useCallback(async (): Promise<void> => {
    try {
      const usr = await withAuthTimeout(
        getFirebaseUser(),
        AUTH_TIMEOUT,
        'getFirebaseUser'
      )

      if (usr?.uid && !usr.isAnonymous) {
        const wllUser = await fetchUserFromDB(
          usr as User,
          getMasterLinkParamsFromLocal,
          toggleShowSnackbar
        )

        if (wllUser) {
          await setUserDataInState(wllUser, setUser, setUserFavorites, setAuthLoading, setBrazeInitialized)
        } else {
          handleAuthError(
            ANALYTICS_TAGS.user_fetch_failed,
            'Failed to fetch or create user in database',
            'handleUserChange',
            { userId: getUserId(usr as User) }
          )
          startTransition(() => {
            setAuthLoading(false)
            setShowLogin({ show: false, extraFields: [] })
          })
          await logout()
          toggleShowSnackbar({
            text: 'Failed to load user profile. Please try logging in again.',
            color: 'red',
          })
        }
      } else {
        await handleAnonymousSignIn()
        startTransition(() => {
          setUser(usr as User)
          setUserFavorites({
            topics: [],
            favPlayers: [],
            favTeam: null,
            favWLLTeam: null,
          })
          setShowLogin({ show: false, extraFields: [] })
          setAuthLoading(false)
        })
      }
    } catch (error) {
      handleAuthError(ANALYTICS_TAGS.user_change_error, error, 'handleUserChange')
      startTransition(() => {
        setAuthLoading(false)
        setShowLogin({ show: false, extraFields: [] })
      })
      toggleShowSnackbar({
        text: 'Error loading user data. Please try again.',
        color: 'red',
      })
    }
  }, [
    getMasterLinkParamsFromLocal,
    logout,
    setAuthLoading,
    setUser,
    setUserFavorites,
    setShowLogin,
    setBrazeInitialized,
    toggleShowSnackbar,
  ])

  const getAuthToken = useCallback(async (): Promise<string | null> => {
    try {
      const auth = await getFirAuth()
      if (!auth) {
        handleAuthError(
          ANALYTICS_TAGS.auth_change_error,
          'Firebase auth not available',
          'getAuthToken'
        )
        return null
      }
      const usr = await getFirebaseUser()
      if (auth?.currentUser && !usr.isAnonymous && usr.uid) {
        return await auth.currentUser.getIdToken()
      }
      return null
    } catch (error) {
      handleAuthError(ANALYTICS_TAGS.auth_change_error, error, 'getAuthToken')
      return null
    }
  }, [])

  const handleCustomToken = useCallback(async (tk: string) => {
    const auth = await getFirAuth()
    if (!tk || !auth) return
    const result = await signInWithCustomToken(auth, tk)
    clearQueryParams(['fbct'])
    if (!result) {
      handleAuthError(ANALYTICS_TAGS.auth_change_error, 'Custom token sign in failed', 'handleCustomToken')
    }
  }, [])

  const getAuthRedirectResult = useCallback(async () => {
    const auth = await getFirAuth()
    if (!auth) return
    const resolver = await getBrowserPopupRedirectResolver()
    if (!resolver) return
    await getRedirectResult(auth, resolver)
  }, [])

  const waitForAuth = useCallback(async () => {
    const { waitForAuthStateReady } = await import(
      /* webpackChunkName: "firebase-connect", webpackPrefetch: true */ '../../Api/firebase/firebaseConnect'
    )
    await waitForAuthStateReady()
  }, [])

  return useMemo(
    () => ({
      handleUserChange,
      logout,
      getAuthToken,
      handleCustomToken,
      getAuthRedirectResult,
      waitForAuth,
    }),
    [
      handleUserChange,
      logout,
      getAuthToken,
      handleCustomToken,
      getAuthRedirectResult,
      waitForAuth,
    ]
  )
}
