import { getFirAuth } from '../../Api/firebase/firebaseConnect'

type AuthWithSettings = { settings?: { appVerificationDisabledForTesting?: boolean } }

/**
 * Configure Firebase Auth for development mode to bypass reCAPTCHA verification.
 * Allows testing phone authentication without solving reCAPTCHA challenges on localhost.
 */
export const configureFirebaseForDevelopment = async (): Promise<void> => {
  if (process.env.NODE_ENV !== 'development') return

  try {
    const auth = await getFirAuth()
    if (auth) {
      const host = window?.location?.hostname
      const isLocal = host === 'localhost' || host === '127.0.0.1'
      if (!isLocal) return
      const authWithSettings = auth as AuthWithSettings
      authWithSettings.settings = authWithSettings.settings || {}
      authWithSettings.settings.appVerificationDisabledForTesting = true
    }
  } catch (err) {
    console.warn('Could not configure Firebase for development:', err)
  }
}
