import { useCallback, useRef, useEffect } from 'react'

type EmailPromptReturn = {
  promptForEmail: () => Promise<string | null>
  handleEmailPromptConfirm: (email: string) => void
  handleEmailPromptCancel: () => void
}

type UseEmailPromptParams = {
  setShowEmailPrompt: (show: boolean) => void
}

export const useEmailPrompt = ({
  setShowEmailPrompt,
}: UseEmailPromptParams): EmailPromptReturn => {
  const emailPromptResolveRef = useRef<((value: string | null) => void) | null>(null)
  const activeEmailPromiseRef = useRef<Promise<string | null> | null>(null)

  useEffect(() => {
    return () => {
      if (emailPromptResolveRef.current) {
        emailPromptResolveRef.current(null)
        emailPromptResolveRef.current = null
      }
      activeEmailPromiseRef.current = null
    }
  }, [])

  const promptForEmail = useCallback((): Promise<string | null> => {
    if (activeEmailPromiseRef.current) {
      return activeEmailPromiseRef.current
    }

    activeEmailPromiseRef.current = new Promise<string | null>((resolve) => {
      emailPromptResolveRef.current = resolve
      setShowEmailPrompt(true)
    }).finally(() => {
      activeEmailPromiseRef.current = null
    })

    return activeEmailPromiseRef.current!
  }, [setShowEmailPrompt])

  const handleEmailPromptConfirm = useCallback(
    (email: string) => {
      if (emailPromptResolveRef.current) {
        emailPromptResolveRef.current(email)
        emailPromptResolveRef.current = null
      }
      setShowEmailPrompt(false)
    },
    [setShowEmailPrompt]
  )

  const handleEmailPromptCancel = useCallback(() => {
    if (emailPromptResolveRef.current) {
      emailPromptResolveRef.current(null)
      emailPromptResolveRef.current = null
    }
    setShowEmailPrompt(false)
  }, [setShowEmailPrompt])

  return {
    promptForEmail,
    handleEmailPromptConfirm,
    handleEmailPromptCancel,
  }
}
