import React, { useState } from 'react'
import { CancelRow, ErrorStyle, InputStyle, MoreDataCon } from './styles'
import { ItmCol } from '../Popovers/UserPopover/styles'
import { TeamSelect } from '../Popovers/UserPopover/TeamSelect/TeamSelect'
import { validateEmail } from './authHelpers'
import { updateUser } from '../../Api'
import { UserUpdateData } from '../../Api/Users/types'
import { Head } from '../Typography/Text.styles'
import { colors } from '../consts'
import { useAuthContext } from '../../Context'

type SignInConProps = {
  onClose?: () => void
  extraFields: string[]
  allowSkip: boolean
  onFinishedSubmit?: () => void
  uiTheme?: 'light' | 'dark'
}

export const SignInMoreData: React.FC<React.PropsWithChildren<SignInConProps>> = ({
  onClose,
  extraFields,
  allowSkip = true,
  onFinishedSubmit,
  uiTheme = 'light',
}) => {
  const auth = useAuthContext()
  const [moreData, setMoreData] = useState<{ [key: string]: string } | null>(null)
  const [errorMsg, setErrorMsg] = useState<{ [key: string]: string }>({})
  const [updating, setUpdating] = useState<boolean>(false)
  const [buttonText, setButtonText] = useState<string>('Submit')

  const handleInputChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
  ) => {
    let val = e.target.value
    let name = e.target.name
    if (!val) {
      setMoreData({ ...moreData, [name]: '' })
      return
    }
    if (name === 'alternateEmail') {
      val = val.toLowerCase()
    }
    setMoreData({ ...moreData, [name]: val })
  }

  const handleTeamChange = (favTeam: string) => {
    if (!favTeam) return
    setMoreData({ ...moreData, favTeam: favTeam.toLowerCase() })
  }

  const handleSubmit = async () => {
    if (!auth.uid || !moreData) return
    let userUpdateData: UserUpdateData = {
      firstName: auth.firstName ? auth.firstName : '',
      lastName: auth.lastName ? auth.lastName : '',
      email: auth.email ? auth.email : '',
      birthday: auth.birthday ? auth.birthday : '',
      tw: auth.tw ? auth.tw : '',
    }
    if (moreData?.alternateEmail) {
      const validated = validateEmail(moreData.alternateEmail)
      if (!validated.errorMsg) {
        setErrorMsg({ ...errorMsg, alternateEmail: '' })
      } else {
        setErrorMsg({ ...errorMsg, alternateEmail: validated.errorMsg })
        return
      }
    }

    //Clean fav Team
    if (moreData.favTeam) {
      moreData.favTeam = moreData.favTeam.toLowerCase()
    }
    userUpdateData = { ...userUpdateData, ...moreData }
    setUpdating(true)
    setButtonText('Submitting...')
    try {
      await updateUser(userUpdateData)
      setUpdating(false)
      setButtonText('Success!')
      auth.updateProfileInState(userUpdateData)
      onFinishedSubmit && onFinishedSubmit()
    } catch (e) {
      console.error('There was an error logging in: ' + e)
      setUpdating(false)
      setButtonText('Submit')
      alert('Something went wrong updating info.')
    }
  }

  const handleSkipClick = () => {
    onClose?.()
  }

  return (
    <MoreDataCon uiTheme={uiTheme}>
      <Head color={uiTheme === 'light' ? colors.text : colors.white} vertMargins={4}>
        Complete your profile
      </Head>
      {extraFields.includes('email') && !auth.email && !auth.alternateEmail && (
        <div className="inputCon">
          <InputStyle
            required
            type="string"
            variant="outlined"
            margin="normal"
            id="temailOutlined"
            name="alternateEmail"
            placeholder="Enter your email"
            value={moreData?.alternateEmail}
            onChange={(e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
              handleInputChange(e)
            }}
          />
          {errorMsg.email && <ErrorStyle>{errorMsg.email}</ErrorStyle>}
        </div>
      )}
      {extraFields.includes('firstName') && !auth.firstName && (
        <div className="multiInputCon">
          <InputStyle
            required
            type="text"
            variant="outlined"
            margin="normal"
            id="tfirstOutlined"
            name="firstName"
            placeholder="First Name"
            value={moreData?.firstName}
            onChange={(e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
              handleInputChange(e)
            }}
          />
          <InputStyle
            required
            type="text"
            variant="outlined"
            margin="normal"
            id="tlastOutlined"
            name="lastName"
            placeholder="Last Name"
            value={moreData?.lastName}
            onChange={(e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
              handleInputChange(e)
            }}
          />
          {errorMsg.name && <ErrorStyle>{errorMsg.name}</ErrorStyle>}
        </div>
      )}
      {extraFields.includes('zip') && !auth.zip && (
        <div className="inputCon">
          <InputStyle
            required
            type="string"
            variant="outlined"
            margin="normal"
            id="tzipOutlined"
            name="zip"
            placeholder="Zipcode"
            value={moreData?.zipcode}
            onChange={(e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
              handleInputChange(e)
            }}
          />
          {errorMsg.zip && <ErrorStyle>{errorMsg.zip}</ErrorStyle>}
        </div>
      )}
      {extraFields.includes('favTeam') && !auth.favTeam && (
        <div className="inputCon">
          <ItmCol>
            <p>Favorite Team</p>
            <TeamSelect
              current={moreData?.favTeam || 'Archers'}
              onChangeTeam={handleTeamChange}
            />
          </ItmCol>
        </div>
      )}
      <button className="submitBtn" onClick={handleSubmit}>
        {buttonText}
      </button>
      {allowSkip && (
        <CancelRow>
          <button
            className="cancelBtn"
            disabled={updating}
            onClick={handleSkipClick}
          >
            later
          </button>
        </CancelRow>
      )}
    </MoreDataCon>
  )
}
