import { colors, fontSizes, zIndex } from '../../consts'
import { styled } from '@mui/system'

type OverlayProps = {
  type: 'dialog' | 'video' | 'popup' | 'slideup'
  orientation?: 'center' | 'bottom'
}

export const ModalOverlay = styled('div')<OverlayProps>(
  ({ type, orientation, theme }) => ({
    position: 'fixed',
    left: 0,
    bottom: 0,
    width: '100%',
    height: type === 'slideup' ? '60vh' : '100%',
    overflow: 'hidden',

    display: 'flex',
    flexDirection: 'column',
    justifyContent: orientation === 'bottom' ? 'flex-end' : 'center',
    alignItems: 'center',

    // layer and background color depends on type
    ...(type === 'slideup' && {
      zIndex: zIndex.loginOverlay,
      backgroundColor: 'none',
    }),
    ...(type === 'dialog' && {
      zIndex: zIndex.loginOverlay,
      backgroundColor: 'rgba(255,255,255,0.8)',
    }),
    ...(type === 'video' && {
      zIndex: zIndex.videoOverlay,
      backgroundColor: 'rgba(0,0,0,0.7)',
      width: '100vw',
      height: '100vh',
    }),
    ...(type === 'popup' && {
      zIndex: zIndex.loginOverlay,
      backgroundColor: 'rgba(0,0,0,0.4)',
    }),
    '& .closeX': {
      position: 'fixed',
      bottom: orientation === 'bottom' ? '50%' : 80,
      right: 20,
      color: colors.white,
      background: colors.text,
      borderRadius: '50%',
      padding: '10px 12px',
      fontSize: 18,
      fontWeight: 800,
      cursor: 'pointer',
      zIndex: 99,
      [theme.breakpoints.down('sm')]: {
        fontSize: 16,
        bottom: orientation === 'bottom' ? '23%' : 70,
        right: 8,
        padding: '8px 10px',
      },
    },
  })
)

export const BottomCon = styled('div')(({ theme }) => ({
  position: 'fixed',
  left: 0,
  right: 0,
  bottom: 0,
  zIndex: 9999,
}))

