import React, { createContext, useContext, useEffect, useMemo, useState } from 'react'
import { fetchActiveBanners } from '../../Api'
import type { Banner } from '../../Api'
import { StorageContext } from '../StorageContext'
import { STORAGE_NAMES } from '../../Constants'

type BannerContextType = {
  banners: Banner[]
}

const BannerContext = createContext<BannerContextType | null>(null)

export const BannerProvider: React.FC<React.PropsWithChildren<unknown>> = ({
  children,
}) => {
  const { isStorageReady, fetchAndCache } = useContext(StorageContext)!
  const [banners, setBanners] = useState<Banner[]>([])

  useEffect(() => {
    if (isStorageReady) {
      void fetchBanners()
    }
  }, [isStorageReady])

  const fetchBanners = async (): Promise<void> => {
    const fetcher = async (): Promise<Banner[]> => {
      const result = await fetchActiveBanners()
      return result
    }

    const onUpdate = (data: Banner[]) => {
      setBanners(data)
    }

    try {
      await fetchAndCache<Banner[]>(STORAGE_NAMES.banners, fetcher, onUpdate)
    } catch (err) {
      console.error('BannerContext fetchBanners error', err)
    }
  }

  const contextValue = useMemo(() => ({ banners }), [banners])

  return (
    <BannerContext.Provider value={contextValue}>
      {children}
    </BannerContext.Provider>
  )
}

export const useBannerContext = (): BannerContextType => {
  const context = useContext(BannerContext)
  if (!context) {
    throw new Error(
      'useBannerContext must be used within a BannerProvider.'
    )
  }
  return context
}
