import { ANALYTICS_TAGS } from '../../Constants/analytics'
import { logEvent } from '../Analytics/firAnalytics'

export const AUTH_TIMEOUT = 10000 // 10 seconds
export const DB_OPERATION_TIMEOUT = 8000 // 8 seconds
export const NETWORK_CHECK_DELAY = 2000 // 2 seconds for network retry

const MAX_RETRIES = 2
const RETRY_DELAY = 1000
const wait = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms))

/**
 * Executes an asynchronous function with retry logic
 * @param asyncOperation The asynchronous function to execute
 * @param errorContext Context for error logging
 * @returns The result of the operation or undefined if all retries fail
 */
export const executeWithRetry = async <T>(
  asyncOperation: () => Promise<T>,
  errorContext: string
): Promise<T | null> => {
  let retries = 0
  while (retries < MAX_RETRIES) {
    try {
      return await asyncOperation()
    } catch (e) {
      retries++
      if (retries === MAX_RETRIES) {
        console.error(
          '[Retry] Failed operation after multiple retries:',
          errorContext,
          e
        )
        logEvent(ANALYTICS_TAGS.max_failed_fetch_reached, {
          error: e,
          context: errorContext,
        })
        return null
      }
      console.warn(
        '[Retry] Operation failed, retrying:',
        errorContext,
        `Attempt ${retries}/${MAX_RETRIES}`
      )
      await wait(RETRY_DELAY * retries)
    }
  }
  return null
}

/**
 * Wraps an async operation with timeout handling
 */
export const withAuthTimeout = async <T>(
  operation: Promise<T>,
  timeoutMs: number,
  operationName: string
): Promise<T> => {
  let timerId: ReturnType<typeof setTimeout>
  const timeoutPromise = new Promise<never>((_, reject) => {
    timerId = setTimeout(
      () => reject(new Error(`${operationName} timed out after ${timeoutMs}ms`)),
      timeoutMs
    )
  })
  try {
    return await Promise.race([operation, timeoutPromise])
  } finally {
    clearTimeout(timerId!)
  }
}

/**
 * Checks if the browser navigator is currently online.
 */
export const isNavigatorOnline = (): boolean => {
  if (typeof window !== 'undefined' && typeof window.navigator !== 'undefined') {
    return window.navigator.onLine
  }
  return true
}
