import { EventGQL } from '../Events/events.types'
import { makeWLLAPIRequest } from '../utils/request'
import { WLL_ENDPOINTS } from '../utils/endpoints'
import type {
  PlayerData,
  PlayerSeasonStats,
} from './player.types'

/** Fetch player profile by slug */
export const fetchWLLPlayerBySlug = async (
  slug: string,
  year: number
): Promise<PlayerData | null> => {
  try {
    const result = await makeWLLAPIRequest<PlayerData>(WLL_ENDPOINTS.PLAYER, {
      pathParams: { slug },
      queryParams: { year },
    })
    if (result == null) return null
    return Array.isArray(result) ? null : result
  } catch {
    return null
  }
}

/** Fetch a player's event stats */
export const fetchWLLPlayerEventStats = async (
  slug: string,
  year: number
): Promise<EventGQL[] | null> => {
  try {
    const result = await makeWLLAPIRequest<EventGQL>(WLL_ENDPOINTS.PLAYER_EVENT_STATS, {
      pathParams: { slug },
      queryParams: { year },
    })
    if (result == null) return null
    return Array.isArray(result) ? result : null
  } catch {
    return null
  }
}

/** Fetch all player season stats for a given year and season segment */
export async function fetchPlayerSeasonStats(
  year: number,
  seasonSegment: string
): Promise<PlayerSeasonStats[]> {
  try {
    const result = await makeWLLAPIRequest<PlayerSeasonStats>(
      WLL_ENDPOINTS.PLAYER_SEASON_STATS,
      { queryParams: { year, seasonSegment } }
    )
    if (result == null) return []
    return Array.isArray(result) ? result : []
  } catch {
    return []
  }
}
