import type {
  ActionCodeSettings,
  Auth,
  AuthCredential,
  AuthProvider,
  PopupRedirectResolver,
  UserCredential,
} from 'firebase/auth'
import { ANALYTICS_TAGS } from '../../Constants/analytics'
import { logEvent } from '../../Utils'

const loadAuth = () =>
  import(
    /* webpackChunkName: "firebase-auth", webpackPrefetch: true */ 'firebase/auth'
  )

export async function signInWithEmailLink(
  auth: Auth,
  email: string,
  emailLink?: string
): Promise<UserCredential | null> {
  try {
    const { signInWithEmailLink: firebaseSignInWithEmailLink } = await loadAuth()
    return await firebaseSignInWithEmailLink(auth, email, emailLink)
  } catch (error) {
    console.error('Error signing in with email link', error)
    return null
  }
}

export async function sendSignInLinkToEmail(
  auth: Auth,
  email: string,
  actionCodeSettings: ActionCodeSettings
): Promise<boolean | null> {
  try {
    const { sendSignInLinkToEmail: firebaseSendSignInLinkToEmail } = await loadAuth()
    await firebaseSendSignInLinkToEmail(auth, email, actionCodeSettings)
    logEvent(ANALYTICS_TAGS.login_verification_send, {
      verification_method: 'email',
    })
    return true
  } catch (error) {
    console.error('Error sending sign in link to email', error)
    return null
  }
}

