import React, { createContext, useState, useEffect, useCallback } from 'react'
import {
  checkStorageOptions,
  logEvent,
  normalizeError,
  retrieveFromCache,
  storeInCache,
} from '../../Utils'
import { StorageOptionsStatus } from '../../Constants'
import { ANALYTICS_TAGS } from '../../Constants/analytics'

type StorageContextType = {
  storageStatuses: StorageOptionsStatus
  isStorageReady: boolean
  store: (key: string, item: any) => Promise<void>
  getStoredData: (
    key: string,
    timeLimit?: number
  ) => Promise<{
    data: any
    refetch: boolean
  }>
  fetchAndCache: <T>(
    key: string,
    fetcher: () => Promise<T>,
    onUpdate: (data: T) => void
  ) => Promise<void>
}

export const StorageContext = createContext<StorageContextType | null>(null)

export const StorageProvider: React.FC<React.PropsWithChildren<unknown>> = ({
  children,
}) => {
  const [storageStatuses, setStorageStatuses] = useState<StorageOptionsStatus>({
    indexedDB: false,
    local: false,
    session: false,
    cookies: false,
  })
  const [isStorageReady, setIsStorageReady] = useState<boolean>(false)

  useEffect(() => {
    const storageOptions = checkStorageOptions()
    setStorageStatuses(storageOptions)
    setIsStorageReady(true)
  }, [])

  const store = async (key: string, item: any): Promise<void> => {
    await storeInCache(key, item, storageStatuses)
  }

  const getStoredData = async (
    key: string,
    timeLimit?: number
  ): Promise<{
    data: any
    refetch: boolean
  }> => {
    const storedData = await retrieveFromCache(key, storageStatuses)
    if (storedData) {
      if (timeLimit) {
        const lastUpdated = new Date(storedData.lastUpdated)
        const shouldRefetch = lastUpdated.getTime() < Date.now() - timeLimit
        return {
          data: storedData?.data,
          refetch: shouldRefetch,
        }
      }
      return {
        data: storedData?.data,
        refetch: false,
      }
    }
    return {
      data: null,
      refetch: true,
    }
  }

  const getRealTimeStorageStatus = () => {
    const status = checkStorageOptions()
    return {
      available: status.indexedDB || status.local || status.session,
      statuses: status,
    }
  }

  const storeWhenReady = useCallback(
    async (key: string, item: unknown) => {
      const currentStatus = getRealTimeStorageStatus()

      if (currentStatus.available) {
        try {
          await storeInCache(key, item, currentStatus.statuses)
          return
        } catch (error) {
          console.error(`Storage failed for key: ${key}:`, error)
        }
      }

      // Exponential backoff if storage not ready
      const delays = [100, 200, 500, 1000, 2000]
      for (const delay of delays) {
        await new Promise((resolve) => setTimeout(resolve, delay))

        const retryStatus = getRealTimeStorageStatus()
        if (retryStatus.available) {
          try {
            await storeInCache(key, item, retryStatus.statuses)
            return
          } catch (error) {
            console.error(`Delayed storage failed for key: ${key}:`, error)
          }
        }
      }
    },
    [storeInCache]
  )

  const fetchAndCache = useCallback(
    async <T,>(
      key: string,
      fetcher: () => Promise<T>,
      onUpdate: (data: T) => void
    ): Promise<void> => {
      let cacheServed = false

      // Immediate cache check with timeout
      if (isStorageReady) {
        try {
          const cachePromise = retrieveFromCache(key, storageStatuses)
          const timeoutPromise = new Promise<{ data: null; timeout: symbol }>(
            (resolve) =>
              setTimeout(() => resolve({ data: null, timeout: Symbol('timeout') }), 150)
          )

          const result = await Promise.race([cachePromise, timeoutPromise])
          if (result?.data) {
            onUpdate(result.data as T)
            cacheServed = true
          }
        } catch (error) {
          // Cache retrieval failed, continue with network
        }
      }

      // Always fetch fresh data
      try {
        const freshData = await fetcher()
        onUpdate(freshData)
        void storeWhenReady(key, freshData)
      } catch (error) {
        if (!cacheServed) {
          const normalizedError = normalizeError(error)
          logEvent(ANALYTICS_TAGS.network_error, {
            context: 'network_fetch_failed',
            key,
            error: normalizedError.message,
          })
        }
      }
    },
    [storageStatuses, retrieveFromCache, isStorageReady, storeWhenReady]
  )

  return (
    <StorageContext.Provider
      value={{
        storageStatuses,
        isStorageReady,
        store,
        getStoredData,
        fetchAndCache,
      }}
    >
      {children}
    </StorageContext.Provider>
  )
}
