import { startTransition } from 'react'
import { getFirAuth } from '../../Api/firebase/firebaseConnect'
import { formatUpdatedUserData } from '../../Api/firebase/AuthData'
import { createUser, getUser, mapFavorites, mapFirebaseUserToAppUser } from '../../Api/Users'
import { initBrazeCore } from '../../Config/Braze/braze.config'
import { validateAuthState, getUserId, USER_AUTH_ISSUES } from './authHelpers'
import { NEW_USER_VALIDATION_CODE } from '../../Constants/auth'
import { ANALYTICS_TAGS } from '../../Constants/analytics'
import { BRAZE_EVENTS } from '../../Constants/analytics'
import type { MasterLinkParams } from '../../Constants'
import type { User, UserFavorites } from '../../Api/Users/types'
import { logEvent } from '../Analytics/firAnalytics'
import { logBrazeEvent } from '../Analytics/brazeAnalytics'
import { normalizeError } from '../errors/errorHelpers'
import { executeWithRetry, withAuthTimeout, isNavigatorOnline } from '../network/networkHelpers'
import {
  NETWORK_CHECK_DELAY,
  DB_OPERATION_TIMEOUT,
} from '../network/networkHelpers'
import { determineMasterParamsToAdd, validateAuthInput, checkUserValidation } from '../User'

/**
 * Fetch user from WLL database with validation and error handling
 */
export const fetchUserFromDB = async (
  firUsr: User,
  getMasterLinkParamsFromLocal: () => MasterLinkParams | null,
  toggleShowSnackbar: (options: {
    text: string
    color: 'red' | 'blue' | 'green'
  }) => void
): Promise<User | null> => {
  try {
    if (!isNavigatorOnline()) {
      logEvent(ANALYTICS_TAGS.user_db_fetch_error, {
        error: 'Network offline',
        userId: getUserId(firUsr),
        product: 'wll',
      })

      await new Promise((resolve) => setTimeout(resolve, NETWORK_CHECK_DELAY))
      if (!isNavigatorOnline()) {
        toggleShowSnackbar({
          text: 'Network connection required. Please check your connection.',
          color: 'red',
        })
        return null
      }
    }

    const dbUser = await executeWithRetry(
      () => fetchUserFromWLLDB(getMasterLinkParamsFromLocal, toggleShowSnackbar),
      `fetchUserFromDB_${getUserId(firUsr)}`
    )

    if (dbUser) {
      const { isValid, issues } = validateAuthState(dbUser)
      if (!isValid) {
        const hasSyncIssue = issues.includes(
          USER_AUTH_ISSUES.USER_MARKED_AS_LOGGED_IN_BUT_NO_ID
        )

        if (hasSyncIssue && issues.length === 1) {
          dbUser.isLoggedIn = true
        } else {
          logEvent(ANALYTICS_TAGS.user_db_fetch_error, {
            error: 'Invalid user data from DB',
            issues,
            userId: getUserId(firUsr),
            product: 'wll',
          })
          return null
        }
      }
    }

    return dbUser
  } catch (error) {
    logEvent(ANALYTICS_TAGS.user_db_fetch_error, {
      error: normalizeError(error),
      userId: getUserId(firUsr),
      product: 'wll',
    })
    return null
  }
}

/**
 * Fetch user from WLL database with retry logic
 */
export const fetchUserFromWLLDB = async (
  getMasterLinkParamsFromLocal: () => MasterLinkParams | null,
  toggleShowSnackbar: (options: {
    text: string
    color: 'red' | 'blue' | 'green'
  }) => void
): Promise<User | null> => {
  try {
    const firUsr = (await getFirAuth())?.currentUser
    if (!firUsr) return null

    const mParams = getMasterLinkParamsFromLocal()
    if (!firUsr.providerData || firUsr.providerData.length === 0) {
      return null
    }

    const loginInput =
      firUsr.providerData[0].providerId !== 'phone'
        ? firUsr?.email
        : firUsr?.phoneNumber
    if (!loginInput) return null

    const validityCode = await validateAuthInput(loginInput, false)
    const isValid = checkUserValidation(validityCode, toggleShowSnackbar)
    if (!isValid) return null

    const isNewUser = validityCode === NEW_USER_VALIDATION_CODE
    const linkParams = determineMasterParamsToAdd(mParams, isNewUser)

    if (isNewUser) {
      const dbUser = await withAuthTimeout(
        createUser(mapFirebaseUserToAppUser(firUsr), linkParams),
        DB_OPERATION_TIMEOUT,
        'createUser'
      )
      return dbUser
    }

    let dbUser = await withAuthTimeout(
      getUser(linkParams),
      DB_OPERATION_TIMEOUT,
      'getUser'
    )
    if (!dbUser) {
      logEvent(ANALYTICS_TAGS.firebase_user_retry_createUser, {
        product: 'wll',
        user: firUsr?.uid,
      })
      const retryLinkParams = determineMasterParamsToAdd(mParams, true)
      dbUser = await createUser(mapFirebaseUserToAppUser(firUsr), retryLinkParams)
    }

    return dbUser
  } catch (error) {
    const firUsr = (await getFirAuth())?.currentUser
    logEvent(ANALYTICS_TAGS.user_db_fetch_error, {
      error: normalizeError(error),
      userId: firUsr?.uid,
      product: 'wll',
    })
    return null
  }
}

/**
 * Set user data in state with proper error handling
 */
export const setUserDataInState = async (
  userRes: User,
  setUser: (user: User) => void,
  setUserFavorites: (favorites: UserFavorites) => void,
  setAuthLoading: (loading: boolean) => void,
  setBrazeInitialized?: (value: boolean) => void
): Promise<void> => {
  try {
    const userAuth = await formatUpdatedUserData(userRes)
    const userFavs = mapFavorites(userRes)
    startTransition(() => {
      setUser(userAuth)
      setUserFavorites(userFavs)
      setAuthLoading(false)
    })

    if (userAuth?.uid) {
      try {
        const success = await initBrazeCore(userAuth.uid)
        if (success) {
          logBrazeEvent(BRAZE_EVENTS.log_in)
          logEvent(BRAZE_EVENTS.log_in)
          startTransition(() => setBrazeInitialized?.(true))
        }
      } catch (brazeError) {
        logEvent(ANALYTICS_TAGS.braze_init_error, {
          error: normalizeError(brazeError),
          userId: userAuth.uid,
          product: 'wll',
        })
      }
    }
  } catch (error) {
    logEvent(ANALYTICS_TAGS.user_state_set_error, {
      error: normalizeError(error),
      product: 'wll',
    })
    startTransition(() => {
      setAuthLoading(false)
    })
  }
}

/**
 * Handle anonymous sign in with proper error handling
 */
export const handleAnonymousSignIn = async (): Promise<void> => {
  try {
    const success = await initBrazeCore()
    if (success) {
      logBrazeEvent(BRAZE_EVENTS.anonymous_session_start)
      logEvent(BRAZE_EVENTS.anonymous_session_start)
    }
  } catch (error) {
    logEvent(ANALYTICS_TAGS.braze_init_error, {
      error: normalizeError(error),
      context: 'handleAnonymousSignIn',
      product: 'wll',
    })
  }
}
