import { useCallback } from 'react'
import { getFirAuth, getActionCodeSettings } from '../../Api/firebase/firebaseConnect'
import { signInWithEmailLink, sendSignInLinkToEmail } from '../../Api/firebase/auth'
import {
  executeWithRetry,
  withAuthTimeout,
  handleAuthError,
  clearQueryParams,
  getStoredTempEmail,
  setStoredTempEmail,
  removeStoredTempEmail,
  getCurrentUrl,
} from '../../Utils'
import { AUTH_TIMEOUT } from '../../Utils/network/networkHelpers'
import { isNavigatorOnline } from '../../Utils/network/networkHelpers'
import { ANALYTICS_TAGS } from '../../Constants/analytics'
import type { EmailAuthOperations } from './types'

export const useEmailAuth = (
  toggleShowSnackbar: (snackbarData: {
    text: string
    color: 'red' | 'blue' | 'green'
  }) => void,
  getCookie: (name: string) => string | null,
  setCookie: (name: string, value: string) => void,
  removeCookie: (name: string) => void,
  promptForEmail: () => Promise<string | null>
): EmailAuthOperations => {
  const handleEmailLink = useCallback(async (): Promise<void> => {
    try {
      const auth = await getFirAuth()
      if (!auth) {
        handleAuthError(
          ANALYTICS_TAGS.auth_change_error,
          'Firebase auth not available',
          'handleEmailLink'
        )
        return
      }

      let email = getStoredTempEmail(getCookie)

      if (!email) {
        const promptedEmail = await promptForEmail()
        if (!promptedEmail) {
          toggleShowSnackbar({
            text: 'Email is required to continue signing in.',
            color: 'red',
          })
          return
        }
        email = promptedEmail
      }

      const result = await signInWithEmailLink(auth, email, getCurrentUrl())

      if (!result) {
        handleAuthError(ANALYTICS_TAGS.login_error, 'Email link sign in failed', 'handleEmailLink', {
          provider: 'email',
        })
        toggleShowSnackbar({
          text: 'Email sign in failed. Please try again or use a different method.',
          color: 'red',
        })
        return
      }

      if (result.user?.uid) {
        removeStoredTempEmail(removeCookie)
        clearQueryParams(['apiKey', 'oobCode', 'mode'])
      }
    } catch (err) {
      handleAuthError(ANALYTICS_TAGS.login_error, err, 'handleEmailLink', {
        provider: 'email',
      })
      toggleShowSnackbar({
        text: 'Email sign in failed. Please try again or use a different method.',
        color: 'red',
      })
    }
  }, [toggleShowSnackbar, getCookie, removeCookie, promptForEmail])

  const signInWithEmLink = useCallback(
    async (redirectTo: string, email: string): Promise<boolean> => {
      try {
        if (!email || !email.includes('@')) {
          toggleShowSnackbar({
            text: 'Please enter a valid email address.',
            color: 'red',
          })
          return false
        }

        if (!isNavigatorOnline()) {
          toggleShowSnackbar({
            text: 'Network connection required. Please check your connection.',
            color: 'red',
          })
          return false
        }

        const auth = await withAuthTimeout(
          getFirAuth(),
          AUTH_TIMEOUT,
          'getFirAuth for email link'
        )

        if (!auth) {
          toggleShowSnackbar({
            text: 'Auth service unavailable. Please try again later.',
            color: 'red',
          })
          return false
        }

        const actionCodeSettings = getActionCodeSettings(redirectTo || getCurrentUrl())

        const sendEmailWithRetry = async (): Promise<boolean> => {
          const result = await withAuthTimeout(
            sendSignInLinkToEmail(auth, email, actionCodeSettings),
            AUTH_TIMEOUT,
            'sendSignInLinkToEmail'
          )
          if (!result) {
            throw new Error('Failed to send sign-in link')
          }
          return true
        }

        const sent = await executeWithRetry(sendEmailWithRetry, `signInWithEmLink_${email}`)
        if (sent !== true) {
          toggleShowSnackbar({
            text: 'Failed to send signin link. Please try again.',
            color: 'red',
          })
          return false
        }
        setStoredTempEmail(email, setCookie)

        return true
      } catch (err) {
        handleAuthError(ANALYTICS_TAGS.login_error, err, 'signInWithEmLink', {
          provider: 'email',
        })
        toggleShowSnackbar({
          text: 'Failed to send signin link. Please try again.',
          color: 'red',
        })
        return false
      }
    },
    [setCookie, toggleShowSnackbar]
  )

  return {
    signInWithEmLink,
    handleEmailLink,
  }
}
