import { useState, useCallback, useRef, useEffect } from 'react'
import { NO_USER } from '../../Api/firebase/AuthData'
import type { User, UserFavorites } from '../../Api/Users/types'
import type { FavType } from '../../Api/firebase/AuthData'
import type { AuthState } from './types'
import { ANALYTICS_TAGS } from '../../Constants/analytics'
import { logEvent } from '../../Utils'

const defaultFavs: UserFavorites = {
  topics: [],
  favPlayers: [],
  favTeam: null,
  favWLLTeam: null,
}

export const useAuthState = () => {
  const isMountedRef = useRef(true)
  const [user, setUser] = useState<User | null>(null)
  const [authLoading, setAuthLoading] = useState<boolean>(true)
  const [userFavorites, setUserFavorites] = useState<UserFavorites>(defaultFavs)
  const [showLogin, setShowLogin] = useState<{
    show: boolean
    extraFields: string[]
  }>({ show: false, extraFields: [] })
  const [signInFlowStep, setSignInFlowStep] = useState<number>(1)
  const [showEmailPrompt, setShowEmailPrompt] = useState<boolean>(false)
  const [brazeInitialized, setBrazeInitialized] = useState<boolean>(false)

  useEffect(() => {
    return () => {
      isMountedRef.current = false
    }
  }, [])

  const safeSetUser = useCallback((newUser: User | null) => {
    if (isMountedRef.current) setUser(newUser)
  }, [])

  const safeSetAuthLoading = useCallback((loading: boolean) => {
    if (isMountedRef.current) setAuthLoading(loading)
  }, [])

  const safeSetUserFavorites = useCallback((favorites: UserFavorites) => {
    if (isMountedRef.current) setUserFavorites(favorites)
  }, [])

  const safeSetShowLogin = useCallback(
    (show: { show: boolean; extraFields: string[] }) => {
      if (isMountedRef.current) {
        if (show.show) logEvent(ANALYTICS_TAGS.login_show)
        setShowLogin(show)
      }
    },
    []
  )

  const safeSetSignInFlowStep = useCallback((step: number) => {
    if (isMountedRef.current) setSignInFlowStep(step)
  }, [])

  const safeSetShowEmailPrompt = useCallback((show: boolean) => {
    if (isMountedRef.current) setShowEmailPrompt(show)
  }, [])

  const safeSetBrazeInitialized = useCallback((value: boolean) => {
    if (isMountedRef.current) setBrazeInitialized(value)
  }, [])

  const updateFavsInState = useCallback(
    (favType: FavType, favorites: string[], favTeam?: string) => {
      if (!isMountedRef.current) return
      setUserFavorites((prevFavs) => {
        const updatedFavs = { ...prevFavs }
        if (favType === 'favPlayers') updatedFavs.favPlayers = favorites
        if (favType === 'topics') updatedFavs.topics = favorites
        if (favType === 'favTeam' && favTeam) updatedFavs.favTeam = favTeam
        if (favType === 'favWLLTeam' && favTeam) updatedFavs.favWLLTeam = favTeam
        return updatedFavs
      })
    },
    []
  )

  const updateProfileInState = useCallback((userItem: Partial<User>) => {
    if (!isMountedRef.current) return
    setUser((currentUser) => {
      if (currentUser === null) return null
      const updatedUser = { ...currentUser, ...userItem }
      if ('favTeam' in userItem) {
        setUserFavorites((prev) => ({ ...prev, favTeam: userItem.favTeam ?? null }))
      }
      if ('favWLLTeam' in userItem) {
        setUserFavorites((prev) => ({
          ...prev,
          favWLLTeam: userItem.favWLLTeam ?? null,
        }))
      }
      return updatedUser
    })
  }, [])

  const updateUserFieldInState = useCallback(
    <K extends keyof User>(fieldName: K, value: User[K]) => {
      if (!isMountedRef.current) return
      setUser((currentUser) => {
        if (currentUser === null) return null
        return { ...currentUser, [fieldName]: value }
      })
    },
    []
  )

  const clearTeamFavorite = useCallback(() => {
    if (!isMountedRef.current) return
    setUserFavorites((prev) => ({ ...prev, favTeam: null }))
  }, [])

  const resetAuthState = useCallback(() => {
    if (!isMountedRef.current) return
    setUser(NO_USER)
    setUserFavorites(defaultFavs)
    setShowLogin({ show: false, extraFields: [] })
    setSignInFlowStep(1)
    setShowEmailPrompt(false)
    setAuthLoading(false)
    setBrazeInitialized(false)
  }, [])

  const login = useCallback(
    (extraFields?: string[]) => {
      safeSetShowLogin({ show: true, extraFields: extraFields ?? [] })
    },
    [safeSetShowLogin]
  )

  const handleToggleLogin = useCallback(() => {
    if (!isMountedRef.current) return
    setShowLogin((prev) => {
      const next = { show: !prev.show, extraFields: [] }
      if (next.show) logEvent(ANALYTICS_TAGS.login_show)
      return next
    })
  }, [])

  const getMissingUserFields = useCallback(
    (fields: string[]): string[] => {
      if (!user || !fields.length) return []
      return fields.filter((field) => !user[field as keyof User])
    },
    [user]
  )

  const authState: AuthState = {
    user,
    userFavorites,
    authLoading,
    showLogin,
    signInFlowStep,
  }

  return {
    ...authState,
    brazeInitialized,
    setUser: safeSetUser,
    setAuthLoading: safeSetAuthLoading,
    setUserFavorites: safeSetUserFavorites,
    setShowLogin: safeSetShowLogin,
    setSignInFlowStep: safeSetSignInFlowStep,
    setShowEmailPrompt: safeSetShowEmailPrompt,
    setBrazeInitialized: safeSetBrazeInitialized,
    updateFavsInState,
    updateProfileInState,
    updateUserFieldInState,
    clearTeamFavorite,
    resetAuthState,
    login,
    handleToggleLogin,
    getMissingUserFields,
    isMountedRef,
    showEmailPrompt,
  }
}
